#pragma once
/**
 * @file placer.h
 * @brief Declares the Placer class, which encapsulates the functionality, data structures,
 * and algorithms required for the (annealing-based) placement stage
 *
 * The Placer class initializes necessary objects, performs an initial placement,
 * and runs simulated annealing optimization. This optimization minimizes
 * wirelength (bounding box) and timing costs to achieve an efficient placement solution.
 *
 * Key features of the Placer class:
 * - Encapsulates all placement-related variables, cost functions, and data structures.
 * - Supports optional NoC (Network-on-Chip) cost optimizations if enabled.
 * - Interfaces with timing analysis, placement delay calculation.
 * - Provides a mechanism for checkpointing the placement state.
 * - Includes debugging and validation utilities to verify the correctness of placement.
 */

#include <functional>
#include <memory>
#include <optional>

#include "annealer.h"
#include "place_checkpoint.h"
#include "PlacementDelayCalculator.h"
#include "placer_state.h"
#include "noc_place_utils.h"
#include "net_cost_handler.h"
#include "interposer_cost_handler.h"
#include "placement_log_printer.h"
#include "PlacerSetupSlacks.h"
#include "PlacerCriticalities.h"
#include "NetPinTimingInvalidator.h"
#include "vtr_random.h"

class BlkLocRegistry;
class FlatPlacementInfo;
namespace vtr {
class ScopedStartFinishTimer;
}

class Placer {
  public:
    Placer(const Netlist<>& net_list,
           std::optional<std::reference_wrapper<const BlkLocRegistry>> init_place,
           const t_placer_opts& placer_opts,
           const t_analysis_opts& analysis_opts,
           const t_noc_opts& noc_opts,
           const IntraLbPbPinLookup& pb_gpin_lookup,
           const ClusteredPinAtomPinsLookup& netlist_pin_lookup,
           const FlatPlacementInfo& flat_placement_info,
           std::shared_ptr<PlaceDelayModel> place_delay_model,
           float anneal_auto_init_t_scale,
           bool cube_bb,
           bool is_flat,
           bool quiet);

    /**
     * @brief Executes the simulated annealing algorithm to optimize placement.
     *
     * This function minimizes placement costs, including bounding box and timing costs,
     * using simulated annealing. During the process, it periodically updates timing information
     * and saves a checkpoint of the best placement encountered.
     *
     * After the simulated annealing completes, the final placement is evaluated against the
     * checkpoint. If the final placement's quality is worse than the checkpoint, the checkpoint
     * is restored. The final placement is then validated for legality.
     */
    void place();

    /**
     * @brief Copies the placement location variables into the global placement context.
     * This method also updates the global routing context with the estimated routing channel utilization.
     */
    void update_global_state();

  private:
    /// Holds placement algorithm parameters
    const t_placer_opts& placer_opts_;
    /// Holds timing analysis parameters
    const t_analysis_opts& analysis_opts_;
    /// Holds NoC-related parameters
    const t_noc_opts& noc_opts_;
    /// Enables fast look-up pb graph pins from block pin indices
    const IntraLbPbPinLookup& pb_gpin_lookup_;
    /// Enables fast look-up of atom pins connect to CLB pins
    const ClusteredPinAtomPinsLookup& netlist_pin_lookup_;
    /// Placement cost terms with their normalization factors and total cost
    t_placer_costs costs_;
    /// Holds timing, runtime, and block location information
    PlacerState placer_state_;
    /// Random number generator used to select random blocks and locations
    vtr::RngContainer rng_;
    /// Computes and updates net bounding box cost
    NetCostHandler net_cost_handler_;
    /// Computes and updates interposer cost terms when the device has interposer cuts
    std::optional<InterposerCostHandler> interposer_cost_handler_;
    /// Compute and updates NoC-related cost terms if NoC optimization is enabled
    std::optional<NocCostHandler> noc_cost_handler_;
    /// A delay model shared between multiple instances of this class.
    std::shared_ptr<PlaceDelayModel> place_delay_model_;
    /// Prints logs during placement
    const PlacementLogPrinter log_printer_;
    /// Indicates if the placement quench phase should be skipped.
    const bool quench_only_;
    /// Indicates if flat routing resource graph and delay model is used. It should be false.
    const bool is_flat_;

    /// Stores a placement state as a retrievable checkpoint in case the placement quality deteriorates later.
    t_placement_checkpoint placement_checkpoint_;
    /**
     * @brief Holds a setup timing analysis engine.
     * Other placement timing objects like PlacerSetupSlacks, PlacerCriticalities, and NetPinTimingInvalidator
     * have a pointer to timing_info. A shared pointer is used to manage the lifetime of the object.
     */
    std::shared_ptr<SetupTimingInfo> timing_info_;
    /// Post-clustering delay calculator. Its API allows extraction of delay for each timing edge.
    std::shared_ptr<PlacementDelayCalculator> placement_delay_calc_;
    /// Stores setup slack of the clustered netlist connections.
    std::unique_ptr<PlacerSetupSlacks> placer_setup_slacks_;
    /// Stores criticalities of the clustered netlist connections.
    std::unique_ptr<PlacerCriticalities> placer_criticalities_;
    /// Used to invalidate timing edges corresponding to the pins of moved blocks.
    std::unique_ptr<NetPinTimingInvalidator> pin_timing_invalidator_;
    /// Stores information about the critical path. This is usually updated after that timing info is updated.
    tatum::TimingPathInfo critical_path_;

    /// Performs random swaps and implements the simulated annealer optimizer.
    std::unique_ptr<PlacementAnnealer> annealer_;

    /* These variables store timing analysis profiling information
     * at different stages of the placement to be printed at the end
     */
    t_timing_analysis_profile_info pre_place_timing_stats_;
    t_timing_analysis_profile_info pre_quench_timing_stats_;
    t_timing_analysis_profile_info post_quench_timing_stats_;

    /* PlacementLogPrinter is made a friend of this class, so it can
     * access its private member variables without getter methods.
     * PlacementLogPrinter holds a constant reference to an object of type
     * Placer to avoid modifying its member variables.
     */
    friend class PlacementLogPrinter;

  private:
    /**
     * @brief Constructs and initializes timing-related objects.
     *
     * This function performs the following steps to set up timing analysis:
     *
     * 1. Constructs a `tatum::DelayCalculator` for post-clustering delay calculations.
     *    This calculator holds a reference to `PlacerTimingContext::connection_delay`,
     *    which contains net delays based on block locations.
     *
     * 2. Creates and stores a `SetupTimingInfo` object in `timing_info_`.
     *    This object utilizes the delay calculator to compute delays on timing edges
     *    and calculate setup times.
     *
     * 3. Constructs `PlacerSetupSlacks` and `PlacerCriticalities` objects,
     *    which translate arrival and required times into slacks and criticalities,
     *    respectively. These objects hold pointers to timing_info_.
     *
     * 4. Creates a `NetPinTimingInvalidator` object to mark timing edges
     *    corresponding to the pins of moved blocks as invalid. This object
     *    holds a pointer to timing_info_.
     *
     * 5. Performs a full timing analysis by marking all pins as invalid.
     *
     * @param net_list The netlist used for iterating over pins.
     * @param analysis_opts Analysis options, including whether to echo the timing graph.
     */
    void alloc_and_init_timing_objects_(const Netlist<>& net_list,
                                        const t_analysis_opts& analysis_opts);

    /**
     * Checks that the placement has not confused our data structures.
     * i.e. the clb and block structures agree about the locations of
     * every block, blocks are in legal spots, etc.  Also recomputes
     * the final placement cost from scratch and makes sure it is
     * within round-off of what we think the cost is.
     */
    void check_place_();

    /**
     * Computes placement costs from scratch to ensure they are
     * within a small error margin of what the incrementally computed
     * costs are.
     *
     * @return Number cost elements, i.e. BB and timing, that falls
     * outside the acceptable round-off error margin.
     */
    int check_placement_costs_();
};

#pragma once

#include "vpr_types.h"

#include "move_generator.h" // movestats
#include "net_cost_handler.h"
#include "manual_move_generator.h"
#include "vtr_random.h"

#include <optional>
#include <tuple>

class PlaceMacros;
class PlacerState;
class t_placer_costs;
struct t_placer_opts;
enum class e_agent_state;

class NocCostHandler;
class InterposerCostHandler;
class NetPinTimingInvalidator;
class PlacerSetupSlacks;

/**
 * These variables keep track of the number of swaps
 * rejected, accepted or aborted. The total number of swap attempts
 * is the sum of the three number.
 */
struct t_swap_stats {
    int num_swap_rejected = 0;
    int num_swap_accepted = 0;
    int num_swap_aborted = 0;
    int num_ts_called = 0;
};

/**
 * @brief Stores variables that are used by the annealing process.
 *
 * This structure is updated by update_annealing_state() on each outer
 * loop iteration. It stores various important variables that need to
 * be accessed during the placement inner loop.
 *
 * Public members:
 *   @param t
 *              Temperature for simulated annealing.
 *   @param alpha
 *              Temperature decays factor (multiplied each outer loop iteration).
 *   @param num_temps
 *              The count of how many temperature iterations have passed.
 *   @param rlim
 *              Range limit for block swaps.
 *              Currently only updated by AUTO_SCHED.
 *   @param crit_exponent
 *              Used by timing-driven placement to "sharpen" the timing criticality.
 *              Depends on rlim. Currently only updated by AUTO_SCHED.
 *   @param move_lim
 *              Current block move limit.
 *   @param move_lim_max
 *              Maximum block move limit.
 *
 * Private members:
 *   @param UPPER_RLIM
 *              The upper limit for the range limiter value.
 *   @param FINAL_RLIM
 *              The final rlim (range limit) is 1, which is the smallest value that
 *              can still make progress, since an rlim of 0 wouldn't allow any swaps.
 *   @param INVERSE_DELTA_RLIM
 *              Used to update crit_exponent. See update_rlim() for more.
 *
 * Mutators:
 *   @param outer_loop_update()
 *              Update the annealing state variables in the placement outer loop.
 *   @param update_rlim(), update_crit_exponent(), update_move_lim()
 *              Inline subroutines used by the main routine outer_loop_update().
 */
class t_annealing_state {
  public:
    float t;
    float alpha;
    int num_temps;

    float rlim;
    float crit_exponent;
    int move_lim;
    int move_lim_max;

  private:
    float UPPER_RLIM;
    float FINAL_RLIM = 1.;
    float INVERSE_DELTA_RLIM;

  public: //Constructor
    t_annealing_state() = default;
    t_annealing_state(float first_t,
                      float first_rlim,
                      int first_move_lim,
                      float first_crit_exponent);

  public: //Mutator
    /**
     * @brief Update the annealing state according to the annealing schedule selected.
     *
     *   USER_SCHED:  A manual fixed schedule with fixed alpha and exit criteria.
     *   AUTO_SCHED:  A more sophisticated schedule where alpha varies based on success ratio.
     *
     * @return True->continues the annealing. False->exits the annealing.
     */
    bool outer_loop_update(float success_rate,
                           const t_placer_costs& costs,
                           const t_placer_opts& placer_opts);

  private: //Mutator
    /**
     * @brief Update the range limiter to keep acceptance prob. near 0.44.
     *
     * Use a floating point rlim to allow gradual transitions at low temps.
     * The range is bounded by 1 (FINAL_RLIM) and the grid size (UPPER_RLIM).
     */
    inline void update_rlim(float success_rate);

    /**
     * @brief Update the criticality exponent.
     *
     * When rlim shrinks towards the FINAL_RLIM value (indicating
     * that we are fine-tuning a more optimized placement), we can
     * focus more on a smaller number of critical connections.
     * To achieve this, we make the crit_exponent sharper, so that
     * critical connections would become more critical than before.
     *
     * We calculate how close rlim is to its final value comparing
     * to its initial value. Then, we apply the same scaling factor
     * on the crit_exponent so that it lands on the suitable value
     * between td_place_exp_first and td_place_exp_last. The scaling
     * factor is calculated and applied linearly.
     */
    inline void update_crit_exponent(const t_placer_opts& placer_opts);
};

/**
 * @brief Struct to hold the results of a swap.
 */
struct t_swap_result {
    e_move_result move_result; ///< The result of the move (e.g. Accept, Reject, etc.)
    double delta_c;            ///< The change in cost that resulted from the swap.
};

/**
 * @class PlacementAnnealer
 * @brief Simulated annealing optimizer for minimizing placement cost via block swaps.
 *
 * @details This class implements simulated annealing to optimize placement cost by swapping clustered blocks.
 * Swaps that reduce the cost are always accepted, while those that increase the cost are accepted
 * with a diminishing probability.
 *
 * The annealing process consists of two nested loops:
 * - The **inner loop** (implemented in `placement_inner_loop()`) performs individual swaps, all evaluated at a fixed temperature.
 * - The **outer loop** adjusts the temperature and determines whether further iterations are needed.
 *
 * Usage workflow:
 * 1. Call `outer_loop_update_timing_info()` to update timing information.
 * 2. Execute `placement_inner_loop()` for swap evaluations.
 * 3. Call `outer_loop_update_state()` to check if more outer loop iterations are needed.
 * 4. Optionally, use `start_quench()` to set the temperature to zero for a greedy optimization (quenching stage),
 *    then repeat steps 1 and 2.
 *
 *    Usage example:
 *    **************************************
 *    PlacementAnnealer annealer(...);
 *
 *    do {
 *      annealer.outer_loop_update_timing_info();
 *      annealer.placement_inner_loop();
 *    } while (annealer.outer_loop_update_state());
 *
 *    annealer.start_quench();
 *    annealer.outer_loop_update_timing_info();
 *    annealer.placement_inner_loop();
 *    **************************************
 */
class PlacementAnnealer {
  public:
    PlacementAnnealer(const t_placer_opts& placer_opts,
                      PlacerState& placer_state,
                      const PlaceMacros& place_macros,
                      t_placer_costs& costs,
                      NetCostHandler& net_cost_handler,
                      std::optional<InterposerCostHandler>& interposer_cost_handler,
                      std::optional<NocCostHandler>& noc_cost_handler,
                      const t_noc_opts& noc_opts,
                      vtr::RngContainer& rng,
                      std::unique_ptr<MoveGenerator>&& move_generator_1,
                      std::unique_ptr<MoveGenerator>&& move_generator_2,
                      const PlaceDelayModel* delay_model,
                      PlacerCriticalities* criticalities,
                      PlacerSetupSlacks* setup_slacks,
                      SetupTimingInfo* timing_info,
                      NetPinTimingInvalidator* pin_timing_invalidator,
                      float auto_init_t_scale,
                      int move_lim);

    /**
     * @brief Contains the inner loop of the simulated annealing that performs
     * a certain number of swaps with a single temperature
     */
    void placement_inner_loop();

    /**
     * @brief Updates the setup slacks and criticalities before the inner loop
     * of the annealing/quench. It also updates normalization factors for different
     * placement cost terms.
     */
    void outer_loop_update_timing_info_and_cost_terms();

    /**
     * @brief Update the annealing state according to the annealing schedule selected.
     * @return True->continues the annealing. False->exits the annealing.
     */
    bool outer_loop_update_state();

    /**
     * @brief Starts the quench stage in simulated annealing by
     * setting the temperature to zero and reverting the move range limit
     * to the initial value.
     */
    void start_quench();

    /// @brief Returns the total number iterations (attempted swaps).
    int get_total_iteration() const;

    /// @brief Return the RL agent's state
    e_agent_state get_agent_state() const;

    /// @brief Returns a constant reference to the annealing state
    const t_annealing_state& get_annealing_state() const;

    /// @brief Returns constant references to different statistics objects
    std::tuple<const t_swap_stats&, const MoveTypeStat&, const t_placer_statistics&> get_stats() const;

    /**
     * @brief Returns MoveAbortionLogger to report how many moves
     * were aborted for each reason.
     * @return A constant reference to a  MoveAbortionLogger object.
     */
    const MoveAbortionLogger& get_move_abortion_logger() const;

  private:
    /**
     * @brief Pick some block and moves it to another spot.
     *
     * If the new location is empty, directly move the block. If the new location
     * is occupied, switch the blocks. Due to the different sizes of the blocks,
     * this block switching may occur for multiple times. It might also cause the
     * current swap attempt to abort due to inability to find suitable locations
     * for moved blocks.
     *
     * The move generator will record all the switched blocks in the variable
     * `blocks_affected`. Afterwards, the move will be assessed by the chosen
     * cost formulation. Currently, there are three ways to assess move cost,
     * which are stored in the enum type `t_place_algorithm`.
     *
     * @return The result of the swap. Such as whether the block swap is accepted,
     *         rejected or aborted.
     */
    t_swap_result try_swap_(MoveGenerator& move_generator,
                            const t_place_algorithm& place_algorithm,
                            bool manual_move_enabled);

    /**
     * @brief Determines whether a move should be accepted or not.
     * Moves with negative delta cost are always accepted, but
     * moves that increase the total cost are accepted with a
     * probability that diminishes as the temperature decreases.
     * @param delta_c The cost difference if the move is accepted.
     * @param t The annealer's temperature.
     * @return Whether the move is accepted or not.
     */
    e_move_result assess_swap_(double delta_c, double t);

    /// @brief Find the starting temperature for the annealing loop.
    float estimate_starting_temperature_();

    /// @brief Estimate the equilibrium temperature for the current placement.
    ///        Used for estimating the starting temperature.
    float estimate_equilibrium_temp_();

    /// @brief Estimate the starting temperature using the cost variance that
    ///        results from a set of trial swaps.
    float estimate_starting_temp_using_cost_variance_();

  private:
    const t_placer_opts& placer_opts_;
    PlacerState& placer_state_;
    const PlaceMacros& place_macros_;
    /// Stores different placement cost terms
    t_placer_costs& costs_;
    /// Computes bounding box for each cluster net
    NetCostHandler& net_cost_handler_;
    /// Computes interposer cost terms when the device has interposer cuts
    std::optional<InterposerCostHandler>& interposer_cost_handler_;
    /// Computes NoC-related cost terms when NoC optimization are enabled
    std::optional<NocCostHandler>& noc_cost_handler_;
    /// Contains weighting factors for NoC-related cost terms
    const t_noc_opts& noc_opts_;
    /// Random number generator for selecting random blocks and random locations
    vtr::RngContainer& rng_;

    /// The move generator used in the first state of RL agent and initial temperature computation
    std::unique_ptr<MoveGenerator> move_generator_1_;
    /// The move generator used in the second state of RL agent
    std::unique_ptr<MoveGenerator> move_generator_2_;
    /// Handles manual swaps proposed by the user through graphical user interface
    ManualMoveGenerator manual_move_generator_;
    /// RL agent state
    e_agent_state agent_state_;

    const PlaceDelayModel* delay_model_;
    PlacerCriticalities* criticalities_;
    PlacerSetupSlacks* setup_slacks_;
    SetupTimingInfo* timing_info_;
    NetPinTimingInvalidator* pin_timing_invalidator_;
    std::unique_ptr<FILE, decltype(&vtr::fclose)> move_stats_file_;
    int outer_crit_iter_count_;

    t_annealing_state annealing_state_;
    /// Swap statistics keep record of the number accepted/rejected/aborted swaps.
    t_swap_stats swap_stats_;
    MoveTypeStat move_type_stats_;
    t_placer_statistics placer_stats_;

    /// Keep record of moved blocks and affected pins in a swap
    t_pl_blocks_to_be_moved blocks_affected_;

  private:
    /**
     * @brief The maximum number of swap attempts before invoking the
     * once-in-a-while placement legality check as well as floating point
     * variables round-offs check.
     */
    static constexpr int MAX_MOVES_BEFORE_RECOMPUTE = 500000;

    /// Specifies how often (after how many swaps) timing information is recomputed
    /// when the annealer isn't in the quench stage
    int inner_recompute_limit_;
    /// Specifies how often timing information is recomputed when the annealer is in the quench stage
    int quench_recompute_limit_;
    /// Used to trigger a BB and NoC cost re-computation from scratch
    int moves_since_cost_recompute_;
    /// Total number of iterations (attempted swaps).
    int tot_iter_;
    /// Indicates whether the annealer has entered into the quench stage
    bool quench_started_;
    /// Indicates whether routing congestion modeling has been started
    bool congestion_modeling_started_;
    /// Indicates whether interposer congestion modeling has been started
    bool interposer_cong_modeling_started_;

    void LOG_MOVE_STATS_HEADER();
    void LOG_MOVE_STATS_PROPOSED();
    void LOG_MOVE_STATS_OUTCOME(double delta_cost, double delta_bb_cost, double delta_td_cost, const char* outcome, const char* reason);

    /**
     * @brief Defines the RL agent's reward function factor constant. This factor controls the weight of bb cost
     * compared to the timing cost in the agent's reward function. The reward is calculated as
     * -1*(1.5-REWARD_BB_TIMING_RELATIVE_WEIGHT)*timing_cost + (1+REWARD_BB_TIMING_RELATIVE_WEIGHT)*bb_cost)
     */
    static constexpr float REWARD_BB_TIMING_RELATIVE_WEIGHT = 0.4;
};

#pragma once
/**
 * @file placer_state.h
 * @brief Contains placer state/data structures referenced by various source files in vpr/src/place.
 * A PlacerState object contains the placement state which is subject to change during the placement stage.
 * During the placement stage, one or multiple local PlacerState objects are created. At the end of the placement stage,
 * one of these object is copied to global placement context (PlacementContext). The PlacementContext,
 * which is declared in vpr_context.h, contains the placement solution. The PlacementContext should not be used before
 * the end of the placement stage.
 */

#include "vpr_context.h"
#include "vpr_net_pins_matrix.h"
#include "vpr_types.h"
#include "PlacerTimingCosts.h"

/**
 * @brief State relating to the timing driven data.
 *
 * These structures are used when the placer is using a timing driven
 * algorithm (placer_opts->place_algorithm.is_timing_driven() == true).
 *
 * Due to the nature of the type of connection_timing_cost, one must
 * use mutable_timing() to access it. For more, see PlacerTimingCosts.
 */
struct PlacerTimingContext : public Context {
    PlacerTimingContext() = delete;

    /**
     * @brief Allocate structures associated with timing driven placement
     * @param placement_is_timing_driven Specifies whether the placement is timing driven.
     */
    PlacerTimingContext(bool placement_is_timing_driven);

    /**
     * @brief Update the connection_timing_cost values from the temporary
     *        values for all connections that have/haven't changed.
     *
     * All the connections have already been gathered by blocks_affected.affected_pins
     * after running the routine find_affected_nets_and_update_costs() in try_swap().
     */
    void commit_td_cost(const t_pl_blocks_to_be_moved& blocks_affected);

    /**
     * @brief Reverts modifications to proposed_connection_delay and proposed_connection_timing_cost
     * based on the move proposed in blocks_affected
     */
    void revert_td_cost(const t_pl_blocks_to_be_moved& blocks_affected);

    /**
     * @brief Net connection delays based on the committed block positions.
     *
     * Index ranges: [0..cluster_ctx.clb_nlist.nets().size()-1][1..num_pins-1]
     */
    NetPinsMatrix<float> connection_delay;

    /**
     * @brief Net connection delays based on the proposed block positions.
     *
     * Only contains meaningful values for connections affected by the proposed
     * move. Otherwise, INVALID_DELAY.
     *
     * Index ranges: [0..cluster_ctx.clb_nlist.nets().size()-1][1..num_pins-1]
     */
    ClbNetPinsMatrix<float> proposed_connection_delay;

    /**
     * @brief Net connection setup slacks based on most recently updated timing graph.
     *
     * Updated with commit_setup_slacks() routine.
     *
     * Index ranges: [0..cluster_ctx.clb_nlist.nets().size()-1][1..num_pins-1]
     */
    ClbNetPinsMatrix<float> connection_setup_slack;

    /**
     * @brief Net connection timing costs (i.e. criticality * delay)
     *        of committed block positions. See PlacerTimingCosts.
     */
    PlacerTimingCosts connection_timing_cost;

    /**
     * @brief Costs for proposed block positions. Only for connection
     *        affected by the proposed move. Otherwise, INVALID_DELAY.
     *
     * Index ranges: [0..cluster_ctx.clb_nlist.nets().size()-1][1..num_pins-1]
     */
    ClbNetPinsMatrix<double> proposed_connection_timing_cost;

    /**
     * @brief Timing cost of nets (i.e. sum of criticality * delay for each net sink/connection).
     *
     * Like connection_timing_cost, but summed across net pins. Used to allow more
     * efficient recalculation of timing cost if only a sub-set of nets are changed
     * while maintaining numeric stability.
     *
     * Index range: [0..cluster_ctx.clb_nlist.nets().size()-1]
     */
    vtr::vector<ClusterNetId, double> net_timing_cost;

    static constexpr float INVALID_DELAY = std::numeric_limits<float>::quiet_NaN();
};

/**
 * @brief State relating to various runtime statistics.
 */
struct PlacerRuntimeContext : public Context {
    float f_update_td_costs_connections_elapsed_sec;
    float f_update_td_costs_nets_elapsed_sec;
    float f_update_td_costs_sum_nets_elapsed_sec;
    float f_update_td_costs_total_elapsed_sec;
};

/**
 * @brief This object encapsulates VPR placer's state.
 *
 * It is divided up into separate sub-contexts of logically related
 * data structures.
 *
 * Typical usage in the VPR placer would be to call the appropriate
 * accessor to get a reference to the context of interest, and then
 * operate on it.
 *
 * See the class VprContext in `vpr_context.h` for descriptions on
 * how to use this class due to similar implementation style.
 */
class PlacerState : public Context {
  public:
    PlacerState(bool placement_is_timing_driven);

  public:
    inline const PlacerTimingContext& timing() const { return timing_; }
    inline PlacerTimingContext& mutable_timing() { return timing_; }

    inline const PlacerRuntimeContext& runtime() const { return runtime_; }
    inline PlacerRuntimeContext& mutable_runtime() { return runtime_; }

    inline const vtr::vector_map<ClusterBlockId, t_block_loc>& block_locs() const { return blk_loc_registry_.block_locs(); }
    inline vtr::vector_map<ClusterBlockId, t_block_loc>& mutable_block_locs() { return blk_loc_registry_.mutable_block_locs(); }

    inline const GridBlock& grid_blocks() const { return blk_loc_registry_.grid_blocks(); }
    inline GridBlock& mutable_grid_blocks() { return blk_loc_registry_.mutable_grid_blocks(); }

    inline const vtr::vector_map<ClusterPinId, int>& physical_pins() const { return blk_loc_registry_.physical_pins(); }
    inline vtr::vector_map<ClusterPinId, int>& mutable_physical_pins() { return blk_loc_registry_.mutable_physical_pins(); }

    inline const BlkLocRegistry& blk_loc_registry() const { return blk_loc_registry_; }
    inline BlkLocRegistry& mutable_blk_loc_registry() { return blk_loc_registry_; }

  private:
    PlacerTimingContext timing_;
    PlacerRuntimeContext runtime_;

    /**
     * @brief Contains: 1) The location where each clustered block is placed at.
     *                  2) Which clustered blocks are located at a given location
     *                  3) The mapping between the clustered block pins and physical tile pins.
     */
    BlkLocRegistry blk_loc_registry_;
};

