31	/**************************************************************************/
32	/*************** Static Function Declarations *****************************/
33	/**************************************************************************/
34	
35	/**
36	 * @brief Check if the setup slack has gotten better or worse due to block swap.
37	 *
38	 * Get all the modified slack values via the PlacerSetupSlacks class, and compare
39	 * then with the original values at these connections. Sort them and compare them
40	 * one by one, and return the difference of the first different pair.
41	 *
42	 * If the new slack value is larger(better), than return a negative value so that
43	 * the move will be accepted. If the new slack value is smaller(worse), return a
44	 * positive value so that the move will be rejected.
45	 *
46	 * If no slack values have changed, then return an arbitrary positive number. A
47	 * move resulting in no change in the slack values should probably be unnecessary.
48	 *
49	 * The sorting is needed to prevent in the unlikely circumstance that a bad slack
50	 * value suddenly got very good due to the block move, while a good slack value
51	 * got very bad, perhaps even worse than the original worse slack value.
52	 */
53	static float analyze_setup_slack_cost(const PlacerSetupSlacks* setup_slacks,
54	                                      const PlacerState& placer_state);
55	
56	/*************************************************************************/
57	/*************** Static Function Definitions *****************************/
58	/*************************************************************************/
59	
60	static float analyze_setup_slack_cost(const PlacerSetupSlacks* setup_slacks,
61	                                      const PlacerState& placer_state) {
62	    const auto& cluster_ctx = g_vpr_ctx.clustering();
63	    const auto& clb_nlist = cluster_ctx.clb_nlist;
64	
65	    const auto& p_timing_ctx = placer_state.timing();
66	    const auto& connection_setup_slack = p_timing_ctx.connection_setup_slack;
67	
68	    //Find the original/proposed setup slacks of pins with modified values
69	    std::vector<float> original_setup_slacks, proposed_setup_slacks;
70	
71	    auto clb_pins_modified = setup_slacks->pins_with_modified_setup_slack();
72	    for (ClusterPinId clb_pin : clb_pins_modified) {
73	        ClusterNetId net_id = clb_nlist.pin_net(clb_pin);
74	        size_t ipin = clb_nlist.pin_net_index(clb_pin);
75	
76	        original_setup_slacks.push_back(connection_setup_slack[net_id][ipin]);
77	        proposed_setup_slacks.push_back(setup_slacks->setup_slack(net_id, ipin));
78	    }
79	
80	    // Sort in ascending order, from the worse slack value to the best
81	    std::ranges::stable_sort(original_setup_slacks);
82	    std::ranges::stable_sort(proposed_setup_slacks);
83	
84	    //Check the first pair of slack values that are different
85	    //If found, return their difference
86	    for (size_t idiff = 0; idiff < original_setup_slacks.size(); ++idiff) {
87	        float slack_diff = original_setup_slacks[idiff] - proposed_setup_slacks[idiff];
88	
89	        if (slack_diff != 0) {
90	            return slack_diff;
91	        }
92	    }
93	
94	    //If all slack values are identical (or no modified slack values),
95	    //reject this move by returning an arbitrary positive number as cost.
96	    return 1;
97	}
