103	///@brief Constructor: Initialize all annealing state variables and macros.
104	t_annealing_state::t_annealing_state(float first_t,
105	                                     float first_rlim,
106	                                     int first_move_lim,
107	                                     float first_crit_exponent) {
108	    num_temps = 0;
109	    alpha = 1.f;
110	    t = first_t;
111	    rlim = first_rlim;
112	    move_lim_max = first_move_lim;
113	    crit_exponent = first_crit_exponent;
114	    move_lim = move_lim_max;
115	
116	    /* Store this inverse value for speed when updating crit_exponent. */
117	    INVERSE_DELTA_RLIM = 1 / (first_rlim - FINAL_RLIM);
118	
119	    /* The range limit cannot exceed the largest grid size. */
120	    const auto& grid = g_vpr_ctx.device().grid;
121	    UPPER_RLIM = std::max(grid.width() - 1, grid.height() - 1);
122	}
123	
124	bool t_annealing_state::outer_loop_update(float success_rate,
125	                                          const t_placer_costs& costs,
126	                                          const t_placer_opts& placer_opts) {
127	#ifndef NO_GRAPHICS
128	    t_draw_state* draw_state = get_draw_state_vars();
129	    if (!draw_state->list_of_breakpoints.empty()) {
130	        // Update temperature in the current information variable.
131	        get_bp_state_globals()->get_glob_breakpoint_state()->temp_count++;
132	    }
133	#endif
134	
135	    if (placer_opts.anneal_sched.type == e_sched_type::USER_SCHED) {
136	        // Update t with user specified alpha.
137	        t *= placer_opts.anneal_sched.alpha_t;
138	
139	        // Check if the exit criterion is met.
140	        bool exit_anneal = t >= placer_opts.anneal_sched.exit_t;
141	
142	        return exit_anneal;
143	    }
144	
145	    // Automatically determine exit temperature.
146	    //
147	    // This heuristic assumes the total placement cost mainly reflects the
148	    // (normalized) bbox and timing terms, which typically makes costs.cost close to ~1.0
149	    // after cost normalization and timing_tradeoff are applied.
150	    //
151	    // When additional cost terms are enabled (e.g. congestion, interposer costs),
152	    // the total cost magnitude increases, so we scale t_exit to keep a comparable
153	    // effective annealing temperature scale; interposer-related factors are only
154	    // included if the device has an interposer.
155	    const ClusteringContext& cluster_ctx = g_vpr_ctx.clustering();
156	    float t_exit = 0.005 * costs.cost / cluster_ctx.clb_nlist.nets().size();
157	    if (g_vpr_ctx.device().grid.has_interposer_cuts()) {
158	        t_exit *= (1. + placer_opts.congestion_factor + placer_opts.interposer_cost_params.net_cost_factor + placer_opts.interposer_cost_params.cong_cost_factor);
159	    } else {
160	        t_exit *= (1. + placer_opts.congestion_factor);
161	    }
162	
163	    VTR_ASSERT_SAFE(placer_opts.anneal_sched.type == e_sched_type::AUTO_SCHED);
164	    // Automatically adjust alpha according to success rate.
165	    if (success_rate > 0.96) {
166	        alpha = 0.5;
167	    } else if (success_rate > 0.8) {
168	        alpha = 0.9;
169	    } else if (success_rate > 0.15 || rlim > 1.) {
170	        alpha = 0.95;
171	    } else {
172	        alpha = 0.8;
173	    }
174	    // Update temp.
175	    t *= alpha;
176	    // Must be duplicated to retain previous behavior.
177	    if (t < t_exit || std::isnan(t_exit)) {
178	        return false;
179	    }
180	
181	    // Update the range limiter.
182	    update_rlim(success_rate);
183	
184	    // If using timing driven algorithm, update the crit_exponent.
185	    if (placer_opts.place_algorithm.is_timing_driven()) {
186	        update_crit_exponent(placer_opts);
187	    }
188	
189	    // Continues the annealing.
190	    return true;
191	}
192	
193	void t_annealing_state::update_rlim(float success_rate) {
194	    rlim *= (1. - 0.44 + success_rate);
195	    rlim = std::min(rlim, UPPER_RLIM);
196	    rlim = std::max(rlim, FINAL_RLIM);
197	}
198	
199	void t_annealing_state::update_crit_exponent(const t_placer_opts& placer_opts) {
200	    // If rlim == FINAL_RLIM, then scale == 0.
201	    float scale = 1 - (rlim - FINAL_RLIM) * INVERSE_DELTA_RLIM;
202	
203	    // Apply the scaling factor on crit_exponent.
204	    crit_exponent = scale * (placer_opts.td_place_exp_last - placer_opts.td_place_exp_first)
205	                    + placer_opts.td_place_exp_first;
206	}
