212	PlacementAnnealer::PlacementAnnealer(const t_placer_opts& placer_opts,
213	                                     PlacerState& placer_state,
214	                                     const PlaceMacros& place_macros,
215	                                     t_placer_costs& costs,
216	                                     NetCostHandler& net_cost_handler,
217	                                     std::optional<InterposerCostHandler>& interposer_cost_handler,
218	                                     std::optional<NocCostHandler>& noc_cost_handler,
219	                                     const t_noc_opts& noc_opts,
220	                                     vtr::RngContainer& rng,
221	                                     std::unique_ptr<MoveGenerator>&& move_generator_1,
222	                                     std::unique_ptr<MoveGenerator>&& move_generator_2,
223	                                     const PlaceDelayModel* delay_model,
224	                                     PlacerCriticalities* criticalities,
225	                                     PlacerSetupSlacks* setup_slacks,
226	                                     SetupTimingInfo* timing_info,
227	                                     NetPinTimingInvalidator* pin_timing_invalidator,
228	                                     float auto_init_t_scale,
229	                                     int move_lim)
230	    : placer_opts_(placer_opts)
231	    , placer_state_(placer_state)
232	    , place_macros_(place_macros)
233	    , costs_(costs)
234	    , net_cost_handler_(net_cost_handler)
235	    , interposer_cost_handler_(interposer_cost_handler)
236	    , noc_cost_handler_(noc_cost_handler)
237	    , noc_opts_(noc_opts)
238	    , rng_(rng)
239	    , move_generator_1_(std::move(move_generator_1))
240	    , move_generator_2_(std::move(move_generator_2))
241	    , manual_move_generator_(placer_state, place_macros, net_cost_handler, rng)
242	    , agent_state_(e_agent_state::EARLY_IN_THE_ANNEAL)
243	    , delay_model_(delay_model)
244	    , criticalities_(criticalities)
245	    , setup_slacks_(setup_slacks)
246	    , timing_info_(timing_info)
247	    , pin_timing_invalidator_(pin_timing_invalidator)
248	    , move_stats_file_(nullptr, vtr::fclose)
249	    , outer_crit_iter_count_(1)
250	    , blocks_affected_(placer_state.block_locs().size())
251	    , quench_started_(false)
252	    , congestion_modeling_started_(false)
253	    , interposer_cong_modeling_started_(false) {
254	    const auto& device_ctx = g_vpr_ctx.device();
255	
256	    float first_crit_exponent;
257	    if (placer_opts.place_algorithm.is_timing_driven()) {
258	        first_crit_exponent = placer_opts.td_place_exp_first; /*this will be modified when rlim starts to change */
259	    } else {
260	        first_crit_exponent = 0.f;
261	    }
262	
263	    int first_move_lim = get_place_inner_loop_num_move(placer_opts, placer_opts_.anneal_sched);
264	
265	    VTR_LOG("Moves per temperature: %d\n", first_move_lim);
266	
267	    if (placer_opts.inner_loop_recompute_divider != 0) {
268	        inner_recompute_limit_ = std::lround((float)first_move_lim / (float)placer_opts.inner_loop_recompute_divider);
269	    } else {
270	        // don't do an inner recompute
271	        inner_recompute_limit_ = first_move_lim + 1;
272	    }
273	
274	    /* calculate the number of moves in the quench that we should recompute timing after based on the value of *
275	     * the commandline option quench_recompute_divider                                                         */
276	    if (placer_opts.quench_recompute_divider != 0) {
277	        quench_recompute_limit_ = std::lround((float)move_lim / (float)placer_opts.quench_recompute_divider);
278	    } else {
279	        // don't do an quench recompute
280	        quench_recompute_limit_ = first_move_lim + 1;
281	    }
282	
283	    moves_since_cost_recompute_ = 0;
284	    tot_iter_ = 0;
285	
286	    // Get the first range limiter
287	    MoveGenerator::first_rlim = (float)std::max(device_ctx.grid.width() - 1, device_ctx.grid.height() - 1);
288	
289	    // In automatic schedule we do a number of random moves before starting the main annealer
290	    // to get an estimate for the initial temperature. We set this temperature low
291	    // to ensure that initial placement quality will be preserved
292	    constexpr float pre_annealing_temp = 1.e-15f;
293	    annealing_state_ = t_annealing_state(pre_annealing_temp,
294	                                         MoveGenerator::first_rlim,
295	                                         first_move_lim,
296	                                         first_crit_exponent);
297	
298	    if (!placer_opts.move_stats_file.empty()) {
299	        move_stats_file_ = std::unique_ptr<FILE, decltype(&vtr::fclose)>(
300	            vtr::fopen(placer_opts.move_stats_file.c_str(), "w"),
301	            vtr::fclose);
302	        LOG_MOVE_STATS_HEADER();
303	    }
304	
305	    //allocate move type statistics vectors
306	    move_type_stats_.blk_type_moves.resize({device_ctx.logical_block_types.size(), (int)e_move_type::NUMBER_OF_AUTO_MOVES}, 0);
307	    move_type_stats_.accepted_moves.resize({device_ctx.logical_block_types.size(), (int)e_move_type::NUMBER_OF_AUTO_MOVES}, 0);
308	    move_type_stats_.rejected_moves.resize({device_ctx.logical_block_types.size(), (int)e_move_type::NUMBER_OF_AUTO_MOVES}, 0);
309	
310	    // Update the starting temperature for placement annealing to a more appropriate value
311	    VTR_ASSERT_SAFE_MSG(auto_init_t_scale >= 0, "Initial temperature scale cannot be negative.");
312	    annealing_state_.t = estimate_starting_temperature_() * auto_init_t_scale;
313	}
314	
315	float PlacementAnnealer::estimate_starting_temperature_() {
316	
317	    if (placer_opts_.anneal_sched.type == e_sched_type::USER_SCHED) {
318	        return placer_opts_.anneal_sched.init_t;
319	    }
320	
321	    switch (placer_opts_.anneal_init_t_estimator) {
322	        case e_anneal_init_t_estimator::COST_VARIANCE:
323	            return estimate_starting_temp_using_cost_variance_();
324	        case e_anneal_init_t_estimator::EQUILIBRIUM:
325	            return estimate_equilibrium_temp_();
326	        default:
327	            VPR_FATAL_ERROR(VPR_ERROR_PLACE,
328	                            "Unrecognized initial temperature estimator type");
329	    };
330	}
331	
332	float PlacementAnnealer::estimate_equilibrium_temp_() {
333	    const ClusteringContext& cluster_ctx = g_vpr_ctx.clustering();
334	
335	    // Determines the block swap loop count.
336	    // TODO: Revisit this. We may be able to get away with doing fewer trial
337	    //       swaps. That or we may be able to get a more accurate initial
338	    //       temperature by doing more moves.
339	    int move_lim = std::min(annealing_state_.move_lim_max, (int)cluster_ctx.clb_nlist.blocks().size());
340	
341	    // Perform N trial swaps and collect the change in cost for each of these
342	    // swaps. Accepted swaps are swaps which resulted in a negative change in
343	    // cost, rejected swaps are swaps which resulted in a positive change in
344	    // cost.
345	    std::vector<double> accepted_swaps;
346	    std::vector<double> rejected_swaps;
347	    accepted_swaps.reserve(move_lim);
348	    rejected_swaps.reserve(move_lim);
349	    for (int i = 0; i < move_lim; i++) {
350	        t_swap_result swap_result = try_swap_(*move_generator_1_,
351	                                              placer_opts_.place_algorithm,
352	                                              false /*manual_move_enabled*/);
353	
354	        if (swap_result.move_result == e_move_result::ACCEPTED) {
355	            accepted_swaps.push_back(swap_result.delta_c);
356	            // TODO: Look into not actually accepting these.
357	            swap_stats_.num_swap_accepted++;
358	        } else if (swap_result.move_result == e_move_result::ABORTED) {
359	            // Note: We do not keep track of the change in cost due to aborted
360	            //       swaps. These are not interesting for this approach.
361	            swap_stats_.num_swap_aborted++;
362	        } else {
363	            rejected_swaps.push_back(swap_result.delta_c);
364	            swap_stats_.num_swap_rejected++;
365	        }
366	    }
367	
368	    // Computed the total change in cost due to accepted swaps.
369	    double total_accepted_cost = 0.0;
370	    for (double accepted_cost : accepted_swaps) {
371	        total_accepted_cost += accepted_cost;
372	    }
373	
374	    // Find the magnitude of the largest reject swap cost. This is useful for
375	    // picking a worst-case initial temperature.
376	    double max_rejected_swap_cost = 0.0;
377	    for (double rejected_cost : rejected_swaps) {
378	        max_rejected_swap_cost = std::max(max_rejected_swap_cost,
379	                                          std::abs(rejected_cost));
380	    }
381	
382	    // Perform a binary search to try and find the equilibrium temperature for
383	    // this placement. This is the temperature that we expect would lead to no
384	    // overall change in temperature. We do this by computing the expected
385	    // change in cost given a trial temperature and try larger / smaller
386	    // temperatures until one is found that causes the change cost is close to
387	    // 0. Since the expected change in cost is monotonically increasing for
388	    // all positive temperatures, this method will return a unique result if it
389	    // exists within this range.
390	    //      Initialize the lower bound temperature to 0. The temperature cannot
391	    //      be less than 0.
392	    double lower_bound_temp = 0.0;
393	    //      Initialize the upper bound temperature. It is possible for
394	    //      the equilibrium temperature to be infinite if the initial placement
395	    //      is so bad that no swaps are accepted. In that case this value will
396	    //      be returned instead of infinity.
397	    //      At this temperature, the probability of accepting this worst rejected
398	    //      swap would be 71.655% (e^(-1/3)).
399	    //      TODO: Investigate if this is a good initial temperature for these
400	    //            cases.
401	    double upper_bound_temp = 3.0 * max_rejected_swap_cost;
402	    //      The max search iterations should never be hit, but it is here as an
403	    //      exit condition to prevent infinite loops.
404	    constexpr unsigned max_search_iters = 100;
405	    for (unsigned binary_search_iter = 0; binary_search_iter < max_search_iters; binary_search_iter++) {
406	        // Exit condition for binary search. Could be hit if the lower and upper
407	        // bounds are arbitrarily close.
408	        if (lower_bound_temp >= upper_bound_temp)
409	            break;
410	
411	        // Try the temperature in the middle of the lower and upper bounds.
412	        double trial_temp = (lower_bound_temp + upper_bound_temp) / 2.0;
413	
414	        // Return the trial temperature if it is within 6 decimal-points of precision.
415	        // NOTE: This is arbitrary.
416	        // TODO: We could stop this early and then use Newton's Method to quickly
417	        //       touch it up to a more accurate value.
418	        if (std::abs(upper_bound_temp - lower_bound_temp) / trial_temp < 1e-6)
419	            return trial_temp;
420	
421	        // Calculate the expected change in cost at this temperature (which we
422	        // call the residual here).
423	        double expected_total_post_rejected_cost = 0.0;
424	        for (double rejected_cost : rejected_swaps) {
425	            // Expected change in cost after a rejected swap is the change in
426	            // cost multiplied by the probability that this swap is accepted at
427	            // this temperature.
428	            double acceptance_prob = std::exp((-1.0 * rejected_cost) / trial_temp);
429	            expected_total_post_rejected_cost += rejected_cost * acceptance_prob;
430	        }
431	        double residual = expected_total_post_rejected_cost + total_accepted_cost;
432	
433	        if (residual < 0) {
434	            // Since the function is monotonically increasing, if the residual
435	            // is negative, then the lower bound should be raised to the trial
436	            // temperature.
437	            lower_bound_temp = trial_temp;
438	        } else if (residual > 0) {
439	            // Similarly, if the residual is positive, then the upper bound should
440	            // be lowered to the trial temperature.
441	            upper_bound_temp = trial_temp;
442	        } else {
443	            // If we happened to exactly hit the risidual, then this is the
444	            // exact temperature we should use.
445	            return trial_temp;
446	        }
447	    }
448	
449	    // If we get down here, it means that the upper loop did not reach a solution;
450	    // however, we know that the answer should be somewhere between lower and upper
451	    // bound. Therefore, return the average of the two.
452	    return (lower_bound_temp + upper_bound_temp) / 2.0;
453	}
454	
455	float PlacementAnnealer::estimate_starting_temp_using_cost_variance_() {
456	    const ClusteringContext& cluster_ctx = g_vpr_ctx.clustering();
457	
458	    // Use to calculate the average of cost when swap is accepted.
459	    int num_accepted = 0;
460	
461	    // Use double types to avoid round off.
462	    double av = 0., sum_of_squares = 0.;
463	
464	    // Determines the block swap loop count.
465	    int move_lim = std::min(annealing_state_.move_lim_max, (int)cluster_ctx.clb_nlist.blocks().size());
466	
467	    bool manual_move_enabled = false;
468	
469	    for (int i = 0; i < move_lim; i++) {
470	#ifndef NO_GRAPHICS
471	        // Checks manual move flag for manual move feature
472	        t_draw_state* draw_state = get_draw_state_vars();
473	        if (draw_state->show_graphics) {
474	            manual_move_enabled = manual_move_is_selected();
475	        }
476	#endif /*NO_GRAPHICS*/
477	
478	        // Will not deploy setup slack analysis, so omit crit_exponenet and setup_slack
479	        t_swap_result swap_result = try_swap_(*move_generator_1_, placer_opts_.place_algorithm, manual_move_enabled);
480	
481	        if (swap_result.move_result == e_move_result::ACCEPTED) {
482	            num_accepted++;
483	            av += costs_.cost;
484	            sum_of_squares += costs_.cost * costs_.cost;
485	            swap_stats_.num_swap_accepted++;
486	        } else if (swap_result.move_result == e_move_result::ABORTED) {
487	            swap_stats_.num_swap_aborted++;
488	        } else {
489	            swap_stats_.num_swap_rejected++;
490	        }
491	    }
492	
493	    // Take the average of the accepted swaps' cost values.
494	    av = num_accepted > 0 ? (av / num_accepted) : 0.;
495	
496	    // Get the standard deviation.
497	    double std_dev = get_std_dev(num_accepted, sum_of_squares, av);
498	
499	    // Improved initial placement uses a fast SA for NoC routers and centroid placement
500	    // for other blocks. The temperature is reduced to prevent SA from destroying the initial placement
501	    float init_temp = std_dev / 64;
502	
503	    return init_temp;
504	}
505	
506	t_swap_result PlacementAnnealer::try_swap_(MoveGenerator& move_generator,
507	                                           const t_place_algorithm& place_algorithm,
508	                                           bool manual_move_enabled) {
509	    /* Picks some block and moves it to another spot.  If this spot is
510	     * occupied, switch the blocks.  Assess the change in cost function.
511	     * rlim is the range limiter.
512	     * Returns whether the swap is accepted, rejected or aborted.
513	     * Passes back the new value of the cost functions.
514	     */
515	    auto& blk_loc_registry = placer_state_.mutable_blk_loc_registry();
516	
517	    // increment the call counter
518	    swap_stats_.num_ts_called++;
519	
520	    PlaceCritParams crit_params{annealing_state_.crit_exponent,
521	                                placer_opts_.place_crit_limit};
522	
523	    // move type and block type chosen by the agent
524	    t_propose_action proposed_action{e_move_type::UNIFORM, -1};
525	
526	    MoveOutcomeStats move_outcome_stats;
527	
528	    double delta_c = 0.;               // Change in cost due to this swap.
529	    t_net_cost_terms cost_terms_delta; // Per-net cost term deltas due to this swap.
530	    double timing_delta_c = 0.;        // Change in the timing cost (delay * criticality).
531	
532	    // Allow some fraction of moves to not be restricted by rlim,
533	    // in the hopes of better escaping local minima.
534	    float rlim;
535	    if (placer_opts_.rlim_escape_fraction > 0. && rng_.frand() < placer_opts_.rlim_escape_fraction) {
536	        rlim = std::numeric_limits<float>::infinity();
537	    } else {
538	        rlim = annealing_state_.rlim;
539	    }
540	
541	    e_create_move create_move_outcome = e_create_move::ABORT;
542	
543	    // Determine whether we need to force swap two NoC router blocks
544	    bool router_block_move = false;
545	    if (noc_opts_.noc) {
546	        router_block_move = check_for_router_swap(noc_opts_.noc_swap_percentage, rng_);
547	    }
548	
549	    // When manual move toggle button is active, the manual move window asks the user for input.
550	    if (manual_move_enabled) {
551	#ifndef NO_GRAPHICS
552	        create_move_outcome = manual_move_display_and_propose(manual_move_generator_, blocks_affected_,
553	                                                              proposed_action.move_type, rlim,
554	                                                              placer_opts_, criticalities_);
555	#endif // NO_GRAPHICS
556	    } else if (router_block_move) {
557	        // generate a move where two random router blocks are swapped
558	        create_move_outcome = propose_router_swap(blocks_affected_, rlim, blk_loc_registry, place_macros_, rng_);
559	        proposed_action.move_type = e_move_type::UNIFORM;
560	    } else {
561	        // Generate a new move (perturbation) used to explore the space of possible placements
562	        create_move_outcome = move_generator.propose_move(blocks_affected_, proposed_action, rlim, placer_opts_, criticalities_);
563	    }
564	
565	    move_type_stats_.incr_blk_type_moves(proposed_action);
566	
567	    if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) LOG_MOVE_STATS_PROPOSED();
568	
569	    VTR_LOGV_DEBUG(g_vpr_ctx.placement().f_placer_debug,
570	                   "\t\tBefore move Place cost %e, bb_cost %e, timing cost %e\n",
571	                   costs_.cost, costs_.bb_cost, costs_.timing_cost);
572	
573	    e_move_result move_outcome = e_move_result::ABORTED;
574	
575	    if (create_move_outcome == e_create_move::ABORT) {
576	        if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) {
577	            LOG_MOVE_STATS_OUTCOME(std::numeric_limits<double>::quiet_NaN(),
578	                                   std::numeric_limits<double>::quiet_NaN(),
579	                                   std::numeric_limits<double>::quiet_NaN(), "ABORTED",
580	                                   "illegal move");
581	        }
582	
583	        move_outcome = e_move_result::ABORTED;
584	
585	    } else {
586	        VTR_ASSERT(create_move_outcome == e_create_move::VALID);
587	
588	        /* To make evaluating the move simpler (e.g. calculating changed bounding box),
589	         * we first move the blocks to their new locations (apply the move to
590	         * blk_loc_registry.block_locs) and then compute the change in cost. If the move
591	         * is accepted, the inverse look-up in blk_loc_registry.grid_blocks is updated
592	         * (committing the move). If the move is rejected, the blocks are returned to
593	         * their original positions (reverting blk_loc_registry.block_locs to its original state).
594	         *
595	         * Note that the inverse look-up blk_loc_registry.grid_blocks is only updated after
596	         * move acceptance is determined, so it should not be used when evaluating a move.
597	         */
598	
599	        // Update the block positions
600	        blk_loc_registry.apply_move_blocks(blocks_affected_);
601	
602	        // Find all the nets affected by this swap and update their wiring costs.
603	        // This cost value doesn't depend on the timing info.
604	        //
605	        // Also find all the pins affected by the swap, and calculates new connection
606	        // delays and timing costs.
607	        net_cost_handler_.find_affected_nets_and_update_costs(delay_model_, criticalities_, blocks_affected_,
608	                                                              cost_terms_delta, timing_delta_c);
609	
610	        const bool update_interposer_costs = interposer_cost_handler_.has_value() && interposer_cost_handler_->has_active_cost_terms();
611	        if (update_interposer_costs) {
612	            const auto [interposer_cost_delta, interposer_cong_cost_delta] = interposer_cost_handler_->total_proposed_cost(net_cost_handler_.affected_nets());
613	            cost_terms_delta.interposer_cost = interposer_cost_delta;
614	            cost_terms_delta.interposer_cong_cost = interposer_cong_cost_delta;
615	        }
616	
617	        if (place_algorithm == e_place_algorithm::CRITICALITY_TIMING_PLACE) {
618	            /* Take delta_c as a combination of timing and wiring cost. In
619	             * addition to `timing_tradeoff`, we normalize the cost values.
620	             * CRITICALITY_TIMING_PLACE algorithm works with somewhat stale
621	             * timing information to save CPU time.
622	             */
623	            VTR_LOGV_DEBUG(g_vpr_ctx.placement().f_placer_debug,
624	                           "\t\tMove bb_delta_c %e, bb_cost_norm %e, timing_tradeoff %f, "
625	                           "timing_delta_c %e, timing_cost_norm %e\n",
626	                           cost_terms_delta.bb_cost,
627	                           costs_.bb_cost_norm,
628	                           placer_opts_.timing_tradeoff,
629	                           timing_delta_c,
630	                           costs_.timing_cost_norm);
631	            delta_c = (1 - placer_opts_.timing_tradeoff) * cost_terms_delta.bb_cost * costs_.bb_cost_norm
632	                      + placer_opts_.timing_tradeoff * timing_delta_c * costs_.timing_cost_norm
633	                      + placer_opts_.congestion_factor * cost_terms_delta.cong_cost * costs_.congestion_cost_norm;
634	            if (update_interposer_costs) {
635	                delta_c += placer_opts_.interposer_cost_params.net_cost_factor * cost_terms_delta.interposer_cost * costs_.interposer_cost_norm
636	                           + placer_opts_.interposer_cost_params.cong_cost_factor * cost_terms_delta.interposer_cong_cost * costs_.interposer_cong_cost_norm;
637	            }
638	        } else if (place_algorithm == e_place_algorithm::SLACK_TIMING_PLACE) {
639	            /* For setup slack analysis, we first do a timing analysis to get the newest
640	             * slack values resulted from the proposed block moves. If the move turns out
641	             * to be accepted, we keep the updated slack values and commit the block moves.
642	             * If rejected, we reject the proposed block moves and revert this timing analysis.
643	             *
644	             * It should be noted that when SLACK_TIMING_PLACE algorithm is used, proposed moves
645	             * are evaluated with up-to-date timing information, which is more expensive but more
646	             * accurate.
647	             */
648	
649	            // Invalidates timing of modified connections for incremental timing updates.
650	            pin_timing_invalidator_->invalidate_affected_connections(blocks_affected_);
651	
652	            /* Update the connection_timing_cost and connection_delay
653	             * values from the temporary values. */
654	            placer_state_.mutable_timing().commit_td_cost(blocks_affected_);
655	
656	            /* Update timing information. Since we are analyzing setup slacks,
657	             * we only update those values and keep the criticalities stale
658	             * so as not to interfere with the original timing driven algorithm.
659	             *
660	             * Note: the timing info must be updated after applying block moves
661	             * and committing the timing driven delays and costs.
662	             * If we wish to revert this timing update due to move rejection,
663	             * we need to revert block moves and restore the timing values. */
664	            criticalities_->disable_update();
665	            setup_slacks_->enable_update();
666	            update_timing_classes(crit_params, timing_info_, criticalities_,
667	                                  setup_slacks_, pin_timing_invalidator_);
668	
669	            /* Get the setup slack analysis cost */
670	            //TODO: calculate a weighted average of the slack cost and wiring cost
671	            delta_c = analyze_setup_slack_cost(setup_slacks_, placer_state_) * costs_.timing_cost_norm;
672	        } else {
673	            VTR_ASSERT_SAFE(place_algorithm == e_place_algorithm::BOUNDING_BOX_PLACE);
674	            VTR_LOGV_DEBUG(g_vpr_ctx.placement().f_placer_debug,
675	                           "\t\tMove bb_delta_c %e, bb_cost_norm %e\n",
676	                           cost_terms_delta.bb_cost,
677	                           costs_.bb_cost_norm);
678	            delta_c = cost_terms_delta.bb_cost * costs_.bb_cost_norm;
679	            if (update_interposer_costs) {
680	                delta_c += placer_opts_.interposer_cost_params.net_cost_factor * cost_terms_delta.interposer_cost * costs_.interposer_cost_norm
681	                           + placer_opts_.interposer_cost_params.cong_cost_factor * cost_terms_delta.interposer_cong_cost * costs_.interposer_cong_cost_norm;
682	            }
683	        }
684	
685	        NocCostTerms noc_delta_c; // change in NoC cost
686	        /* Update the NoC data structure and costs*/
687	        if (noc_opts_.noc) {
688	            VTR_ASSERT_SAFE(noc_cost_handler_.has_value());
689	            noc_cost_handler_->find_affected_noc_routers_and_update_noc_costs(blocks_affected_, noc_delta_c);
690	
691	            // Include the NoC delta costs in the total cost change for this swap
692	            delta_c += calculate_noc_cost(noc_delta_c, costs_.noc_cost_norm_factors, noc_opts_);
693	        }
694	
695	        // determine whether the move is accepted or rejected
696	        move_outcome = assess_swap_(delta_c, annealing_state_.t);
697	
698	        //Updates the manual_move_state members and displays costs to the user to decide whether to ACCEPT/REJECT manual move.
699	#ifndef NO_GRAPHICS
700	        if (manual_move_enabled) {
701	            move_outcome = pl_do_manual_move(delta_c, timing_delta_c, cost_terms_delta.bb_cost, move_outcome);
702	        }
703	#endif //NO_GRAPHICS
704	
705	        if (move_outcome == e_move_result::ACCEPTED) {
706	            costs_.cost += delta_c;
707	            costs_.bb_cost += cost_terms_delta.bb_cost;
708	            costs_.congestion_cost += cost_terms_delta.cong_cost;
709	            if (update_interposer_costs) {
710	                costs_.interposer_cost += cost_terms_delta.interposer_cost;
711	                costs_.interposer_cong_cost += cost_terms_delta.interposer_cong_cost;
712	            }
713	            if (place_algorithm == e_place_algorithm::CRITICALITY_TIMING_PLACE) {
714	                costs_.timing_cost += timing_delta_c;
715	
716	                /* Invalidates timing of modified connections for incremental
717	                 * timing updates. These invalidations are accumulated for a
718	                 * big timing update in the outer loop. */
719	                pin_timing_invalidator_->invalidate_affected_connections(blocks_affected_);
720	
721	                /* Update the connection_timing_cost and connection_delay
722	                 * values from the temporary values. */
723	                placer_state_.mutable_timing().commit_td_cost(blocks_affected_);
724	
725	            } else if (place_algorithm == e_place_algorithm::SLACK_TIMING_PLACE) {
726	                // Update the timing driven cost as usual
727	                costs_.timing_cost += timing_delta_c;
728	
729	                // Commit the setup slack information
730	                // The timing delay and cost values should be committed already
731	                commit_setup_slacks(setup_slacks_, placer_state_);
732	            }
733	
734	            // Update net cost functions and reset flags.
735	            net_cost_handler_.update_move_nets();
736	            if (update_interposer_costs) {
737	                interposer_cost_handler_->commit_costs(net_cost_handler_.affected_nets());
738	            }
739	
740	            // Update clb data structures since we kept the move.
741	            blk_loc_registry.commit_move_blocks(blocks_affected_);
742	
743	            if (noc_opts_.noc) {
744	                noc_cost_handler_->commit_noc_costs();
745	                costs_ += noc_delta_c;
746	            }
747	
748	            //Highlights the new block when manual move is selected.
749	#ifndef NO_GRAPHICS
750	            if (manual_move_enabled) {
751	                manual_move_highlight_new_block_location();
752	            }
753	#endif //NO_GRAPHICS
754	
755	        } else {
756	            VTR_ASSERT_SAFE(move_outcome == e_move_result::REJECTED);
757	
758	            // Reset the net cost function flags first.
759	            net_cost_handler_.reset_move_nets();
760	
761	            // Restore the blk_loc_registry.block_locs data structures to their state before the move.
762	            blk_loc_registry.revert_move_blocks(blocks_affected_);
763	
764	            if (place_algorithm == e_place_algorithm::CRITICALITY_TIMING_PLACE) {
765	                // Un-stage the values stored in proposed_* data structures
766	                placer_state_.mutable_timing().revert_td_cost(blocks_affected_);
767	            } else if (place_algorithm == e_place_algorithm::SLACK_TIMING_PLACE) {
768	                /* Revert the timing delays and costs to pre-update values.
769	                 * These routines must be called after reverting the block moves.
770	                 */
771	                //TODO: make this process incremental
772	                comp_td_connection_delays(delay_model_, placer_state_);
773	                comp_td_costs(delay_model_, *criticalities_, placer_state_, &costs_.timing_cost);
774	
775	                /* Re-invalidate the affected sink pins since the proposed
776	                 * move is rejected, and the same blocks are reverted to
777	                 * their original positions. */
778	                pin_timing_invalidator_->invalidate_affected_connections(blocks_affected_);
779	
780	                // Revert the timing update
781	                update_timing_classes(crit_params, timing_info_, criticalities_,
782	                                      setup_slacks_, pin_timing_invalidator_);
783	
784	                VTR_ASSERT_SAFE_MSG(
785	                    verify_connection_setup_slacks(setup_slacks_, placer_state_),
786	                    "The current setup slacks should be identical to the values before the try swap timing info update.");
787	            }
788	
789	            // Revert the traffic flow routes within the NoC
790	            if (noc_opts_.noc) {
791	                noc_cost_handler_->revert_noc_traffic_flow_routes(blocks_affected_);
792	            }
793	        }
794	
795	        move_type_stats_.incr_accept_reject(proposed_action, move_outcome);
796	
797	        move_outcome_stats.delta_cost_norm = delta_c;
798	        move_outcome_stats.delta_bb_cost_norm = cost_terms_delta.bb_cost * costs_.bb_cost_norm;
799	        move_outcome_stats.delta_timing_cost_norm = timing_delta_c * costs_.timing_cost_norm;
800	
801	        move_outcome_stats.delta_bb_cost_abs = cost_terms_delta.bb_cost;
802	        move_outcome_stats.delta_timing_cost_abs = timing_delta_c;
803	
804	        if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) {
805	            LOG_MOVE_STATS_OUTCOME(delta_c, cost_terms_delta.bb_cost, timing_delta_c, (move_outcome == e_move_result::ACCEPTED ? "ACCEPTED" : "REJECTED"), "");
806	        }
807	    }
808	    move_outcome_stats.outcome = move_outcome;
809	
810	    // If we force a router block move or manual move then it was not proposed
811	    // by the move generator, so we should not calculate the reward and update
812	    // the move generators status since this outcome is not a direct
813	    // consequence of the move generator.
814	    if (!router_block_move && !manual_move_enabled) {
815	        move_generator.calculate_reward_and_process_outcome(move_outcome_stats, delta_c, REWARD_BB_TIMING_RELATIVE_WEIGHT);
816	    }
817	
818	#ifndef NO_GRAPHICS
819	    stop_placement_and_check_breakpoints(blocks_affected_, move_outcome, delta_c, cost_terms_delta.bb_cost, timing_delta_c);
820	#endif
821	
822	    // Clear the data structure containing block move info
823	    blocks_affected_.clear_move_blocks();
824	
825	    VTR_LOGV_DEBUG(g_vpr_ctx.placement().f_placer_debug,
826	                   "\t\tAfter move Place cost %e, bb_cost %e, timing cost %e\n",
827	                   costs_.cost, costs_.bb_cost, costs_.timing_cost);
828	
829	    t_swap_result swap_result;
830	    swap_result.move_result = move_outcome;
831	    swap_result.delta_c = delta_c;
832	    return swap_result;
833	}
834	
835	void PlacementAnnealer::outer_loop_update_timing_info_and_cost_terms() {
836	    if (placer_opts_.place_algorithm.is_timing_driven()) {
837	        /* At each temperature change we update these values to be used
838	         * for normalizing the tradeoff between timing and wirelength (bb) */
839	        if (outer_crit_iter_count_ >= placer_opts_.recompute_crit_iter || placer_opts_.inner_loop_recompute_divider != 0) {
840	
841	            PlaceCritParams crit_params{annealing_state_.crit_exponent,
842	                                        placer_opts_.place_crit_limit};
843	
844	            // Update all timing related classes
845	            perform_full_timing_update(crit_params, delay_model_, criticalities_, setup_slacks_,
846	                                       pin_timing_invalidator_, timing_info_, &costs_, placer_state_);
847	
848	            outer_crit_iter_count_ = 0;
849	        }
850	        outer_crit_iter_count_++;
851	    }
852	
853	    // Congestion modeling is enabled when the ratio of the current range limit to the initial range limit
854	    // drops below a user-specified threshold, and the congestion cost weighting factor is non-zero.
855	    // Once enabled, congestion modeling continues even if the range limit increases and the ratio
856	    // rises above the threshold.
857	    //
858	    // This logic is motivated by the observation that enabling congestion modeling too early in the
859	    // anneal increases computational overhead and introduces noise into the placement cost function,
860	    // as early placements are typically highly congested and unstable. So, we delay congestion modeling
861	    // until the placement is more settled and wirelength has been reasonably optimized.
862	    if ((annealing_state_.rlim / MoveGenerator::first_rlim < placer_opts_.congestion_rlim_trigger_ratio
863	         && placer_opts_.congestion_factor > 0.)
864	        || congestion_modeling_started_) {
865	        costs_.congestion_cost = net_cost_handler_.estimate_routing_chan_util();
866	
867	        if (!congestion_modeling_started_) {
868	            VTR_LOG("Congestion modeling started.\n");
869	            congestion_modeling_started_ = true;
870	        }
871	    }
872	
873	    // Similar to congestion modeling: trigger interposer congestion estimation once rlim shrinks enough (or once started, keep updating).
874	    if ((placer_opts_.interposer_cost_params.cong_cost_factor > 0.
875	         && g_vpr_ctx.device().grid.has_interposer_cuts()
876	         && annealing_state_.rlim / MoveGenerator::first_rlim < placer_opts_.congestion_rlim_trigger_ratio)
877	        || interposer_cong_modeling_started_) {
878	        VTR_ASSERT_SAFE(interposer_cost_handler_.has_value());
879	        costs_.interposer_cong_cost = interposer_cost_handler_->compute_interposer_est_cong(/*compute_congestion_cost=*/true);
880	        if (!interposer_cong_modeling_started_) {
881	            VTR_LOG("Interposer congestion modeling started.\n");
882	            interposer_cong_modeling_started_ = true;
883	        }
884	    }
885	
886	    // Interposer net cost has a two stage mode
887	    // If interposer cost is active, try going to the second stage if case we're in the two stage mode.
888	    if (interposer_cost_handler_ && interposer_cost_handler_->has_active_cost_terms()) {
889	        if (interposer_cost_handler_->try_change_interposer_cost_model(costs_.interposer_cost)) {
890	            VTR_LOG("Changed interposer net cost model.\n");
891	            // Must recompute costs from scratch since cost formula has changed
892	            const auto [interposer_cost, interposer_cong_cost] = interposer_cost_handler_->recompute_costs();
893	            costs_.interposer_cost = interposer_cost;
894	            costs_.interposer_cong_cost = interposer_cong_cost;
895	        }
896	    }
897	
898	    // Update the cost normalization factors
899	    costs_.update_norm_factors();
900	
901	    // update the current total placement cost
902	    costs_.cost = costs_.get_total_cost(placer_opts_, noc_opts_);
903	}
904	
905	void PlacementAnnealer::placement_inner_loop() {
906	    // How many times have we dumped placement to a file this temperature?
907	    int inner_placement_save_count = 0;
908	
909	    placer_stats_.reset();
910	
911	    bool manual_move_enabled = false;
912	
913	    MoveGenerator& move_generator = select_move_generator(move_generator_1_, move_generator_2_, agent_state_,
914	                                                          placer_opts_, quench_started_);
915	
916	    // Inner loop begins
917	    for (int inner_iter = 0, inner_crit_iter_count = 1; inner_iter < annealing_state_.move_lim; inner_iter++) {
918	#ifndef NO_GRAPHICS
919	        // Checks manual move flag for manual move feature
920	        t_draw_state* draw_state = get_draw_state_vars();
921	        if (draw_state->show_graphics) {
922	            manual_move_enabled = manual_move_is_selected();
923	        }
924	#endif /*NO_GRAPHICS*/
925	
926	        t_swap_result swap_result = try_swap_(move_generator, placer_opts_.place_algorithm, manual_move_enabled);
927	
928	        if (swap_result.move_result == e_move_result::ACCEPTED) {
929	            // Move was accepted.  Update statistics that are useful for the annealing schedule.
930	            placer_stats_.single_swap_update(costs_);
931	            swap_stats_.num_swap_accepted++;
932	        } else if (swap_result.move_result == e_move_result::ABORTED) {
933	            swap_stats_.num_swap_aborted++;
934	        } else { // swap_result == REJECTED
935	            swap_stats_.num_swap_rejected++;
936	        }
937	
938	        if (placer_opts_.place_algorithm.is_timing_driven()) {
939	            /* Do we want to re-timing analyze the circuit to get updated slack and criticality values?
940	             * We do this only once in a while, since it is expensive.
941	             */
942	            const int recompute_limit = quench_started_ ? quench_recompute_limit_ : inner_recompute_limit_;
943	            // on last iteration don't recompute
944	            if (inner_crit_iter_count >= recompute_limit && inner_iter != annealing_state_.move_lim - 1) {
945	
946	                inner_crit_iter_count = 0;
947	
948	                PlaceCritParams crit_params{annealing_state_.crit_exponent,
949	                                            placer_opts_.place_crit_limit};
950	
951	                // Update all timing related classes
952	                perform_full_timing_update(crit_params, delay_model_, criticalities_,
953	                                           setup_slacks_, pin_timing_invalidator_,
954	                                           timing_info_, &costs_, placer_state_);
955	            }
956	            inner_crit_iter_count++;
957	        }
958	
959	        /* Lines below prevent too much round-off error from accumulating
960	         * in the cost over many iterations (due to incremental updates).
961	         * This round-off can lead to error checks failing because the cost
962	         * is different from what you get when you recompute from scratch.
963	         */
964	        moves_since_cost_recompute_++;
965	        if (moves_since_cost_recompute_ > MAX_MOVES_BEFORE_RECOMPUTE) {
966	            net_cost_handler_.recompute_costs_from_scratch(delay_model_, criticalities_, costs_);
967	
968	            if (interposer_cost_handler_.has_value()) {
969	                const auto [interposer_cost, interposer_cong_cost] = interposer_cost_handler_->total_committed_cost();
970	                costs_.interposer_cost = interposer_cost;
971	                costs_.interposer_cong_cost = interposer_cong_cost;
972	            }
973	
974	            if (noc_cost_handler_.has_value()) {
975	                noc_cost_handler_->recompute_costs_from_scratch(noc_opts_, costs_);
976	            }
977	
978	            moves_since_cost_recompute_ = 0;
979	        }
980	
981	        if (placer_opts_.placement_saves_per_temperature >= 1 && inner_iter > 0
982	            && (inner_iter + 1) % (annealing_state_.move_lim / placer_opts_.placement_saves_per_temperature) == 0) {
983	            std::string filename = vtr::string_fmt("placement_%03d_%03d.place",
984	                                                   annealing_state_.num_temps + 1, inner_placement_save_count);
985	            VTR_LOG("Saving placement to file at temperature move %d / %d: %s\n",
986	                    inner_iter, annealing_state_.move_lim, filename.c_str());
987	            print_place(nullptr, nullptr, filename.c_str(), placer_state_.block_locs());
988	            ++inner_placement_save_count;
989	        }
990	    }
991	
992	#ifdef VPR_USE_SIGACTION
993	    // Save the block locations after each inner loop for checkpointing.
994	    g_vpr_ctx.mutable_placement().mutable_block_locs() = placer_state_.block_locs();
995	#endif
996	
997	    // Calculate the success_rate and std_dev of the costs.
998	    placer_stats_.calc_iteration_stats(costs_, annealing_state_.move_lim);
999	
1000	    // update the RL agent's state
1001	    if (!quench_started_) {
1002	        if (placer_opts_.place_algorithm.is_timing_driven() && placer_opts_.place_agent_multistate && agent_state_ == e_agent_state::EARLY_IN_THE_ANNEAL) {
1003	            if (annealing_state_.alpha < 0.85 && annealing_state_.alpha > 0.6) {
1004	                agent_state_ = e_agent_state::LATE_IN_THE_ANNEAL;
1005	                VTR_LOG("Agent's 2nd state: \n");
1006	            }
1007	        }
1008	    }
1009	
1010	    tot_iter_ += annealing_state_.move_lim;
1011	    ++annealing_state_.num_temps;
1012	}
