1121	        VTR_LOGV_DEBUG(g_vpr_ctx.placement().f_placer_debug, "\t\tMove is accepted(hill climbing)\n");
1122	        return e_move_result::ACCEPTED;
1123	    }
1124	    VTR_LOGV_DEBUG(g_vpr_ctx.placement().f_placer_debug, "\t\tMove is rejected(hill climbing)\n");
1125	    return e_move_result::REJECTED;
